import 'package:flutter_secure_storage/flutter_secure_storage.dart';
import 'package:path_provider/path_provider.dart';

class PaymentProcessor {
  static const String _storageKey = 'payment_token';

  Future<String> getPaymentToken() async {
    final storage = FlutterSecureStorage();
    return await storage.read(key: _storageKey);
  }

  Future<void> savePaymentToken(String token) async {
    final storage = FlutterSecureStorage();
    await storage.write(key: _storageKey, value: token);
  }

  Future<void> processPayment({
    required String paymentMethod,
    required double amount,
  }) async {
    if (paymentMethod == 'mobile_wallet') {
      // Mobile wallet integration
      final mobileWalletToken = await getMobileWalletToken();
      final response = await postToPaymentGateway(
        token: mobileWalletToken,
        amount: amount,
      );
      if (response['success']) {
        savePaymentToken(response['token']);
      } else {
        throw Exception('Failed to process payment');
      }
    } else if (paymentMethod == 'in_app_purchase') {
      // In-app purchase integration
      final inAppPurchaseResponse = await postToInAppPurchaseGateway(
        amount: amount,
      );
      if (inAppPurchaseResponse['success']) {
        savePaymentToken(inAppPurchaseResponse['token']);
      } else {
        throw Exception('Failed to process payment');
      }
    } else {
      throw Exception('Unsupported payment method');
    }
  }

  Future<String> getMobileWalletToken() async {
    final directory = await getApplicationDocumentsDirectory();
    final file = File('${directory.path}/mobile_wallet_token.txt');
    if (await file.exists()) {
      return await file.readAsString();
    } else {
      throw Exception('No mobile wallet token found');
    }
  }

  Future<Map<String, dynamic>> postToPaymentGateway({
    required String token,
    required double amount,
  }) async {
    final response = await http.post(
      Uri.parse('https://payment-gateway.com/transaction'),
      headers: {
        'Authorization': 'Bearer $token',
      },
      body: jsonEncode({'amount': amount}),
    );
    return jsonDecode(response.body);
  }

  Future<Map<String, dynamic>> postToInAppPurchaseGateway({
    required double amount,
  }) async {
    final response = await http.post(
      Uri.parse('https://in_app_purchase_gateway.com/transaction'),
      body: jsonEncode({'amount': amount}),
    );
    return jsonDecode(response.body);
  }
}